# apply-callai-govtask-patch.ps1
# call-ai.js에 GOV_TASK 태그 파서(_handleGovTaskTags)를 추가하고
# 호출부에 등록한다. Base64+BOM 방식.

$ErrorActionPreference = 'Stop'
try { [Console]::OutputEncoding = [System.Text.Encoding]::UTF8 } catch {}
function _b64d($s) { [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($s)) }
$path = ".\src\gopang\ai\call-ai.js"
if (-not (Test-Path $path)) { throw "call-ai.js를 찾을 수 없습니다 — 리포 루트에서 실행하세요(경로: src\gopang\ai\call-ai.js)." }
$encRead  = [System.Text.Encoding]::UTF8
$encWrite = New-Object System.Text.UTF8Encoding($true)
$content = [System.IO.File]::ReadAllText((Resolve-Path $path), $encRead)
$backupPath = ".\call-ai.js.bak-$(Get-Date -Format yyyyMMdd-HHmmss)"
Copy-Item $path $backupPath
Write-Host "백업 생성: $backupPath"

$funcOldB64 = "ICB9CgogIHJldHVybiBmYWxzZTsKfQoKLyoqCiAqIF9idWlsZEZpcnN0Q29udGFjdENvbnRleHQ="
$funcNewB64 = ""
$callOldB64 = "ICAgIGNvbnN0IF9zcEF1dGhvckhhbmRsZWQgPSBhd2FpdCBfaGFuZGxlU1BBdXRob3JUYWdzKGZ1bGxSZXBseSwgYnViYmxlLCBjYWxsQUksIHVzZXJUZXh0KTsKICAgIGlmIChfc3BBdXRob3JIYW5kbGVkKSByZXR1cm47Cg=="
$callNewB64 = ""

$funcOld = _b64d $funcOldB64
$funcNew = _b64d $funcNewB64
$callOld = _b64d $callOldB64
$callNew = _b64d $callNewB64

if ($funcOld -notmatch 'return false') { throw 'Base64 디코딩 결과 이상 — PowerShell 버전을 확인하세요.' }

$replacements = @(
  @{ Name = '_handleGovTaskTags 함수 정의 삽입'; Old = $funcOld; New = $funcNew },
  @{ Name = '호출부 등록(_spAuthorHandled 다음)'; Old = $callOld; New = $callNew }
)
$applied = 0
foreach ($r in $replacements) {
  if ($content.Contains($r.Old)) {
    $content = $content.Replace($r.Old, $r.New)
    Write-Host "✅ $($r.Name) 치환 완료"
    $applied++
  } else {
    Write-Warning "⚠️ $($r.Name) — 원본과 일치하는 블록을 못 찾았습니다."
  }
}
if ($applied -gt 0) {
  [System.IO.File]::WriteAllText((Resolve-Path $path), $content, $encWrite)
  Write-Host "`ncall-ai.js 저장 완료 (${applied}/2 블록 치환됨)"
} else {
  Write-Host "`n치환된 블록이 없어 파일을 다시 쓰지 않았습니다."
}
Write-Host "`n확인(Node.js 있는 경우): Copy-Item src\gopang\ai\call-ai.js $env:TEMP\ca-check.mjs; node --check $env:TEMP\ca-check.mjs"
